import { useEffect, useState } from "react";
import axios from "axios";
import { MapContainer, TileLayer, Popup, Circle, useMap } from "react-leaflet";
import "leaflet/dist/leaflet.css";

function ChangeMapView({ coords }) {
  const map = useMap();

  useEffect(() => {
    if (coords) {
      map.setView(coords, 15);
    }
  }, [coords, map]);

  return null;
}

export default function PoliceDashboard() {

  const [alerts, setAlerts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [selectedLocation, setSelectedLocation] = useState(null);

  const loadAlerts = () => {
    axios.get("http://127.0.0.1:8000/api/admin-alerts/") // SAME API FOR ALL
      .then(res => {
        setAlerts(res.data);
        setLoading(false);
      })
      .catch(() => {
        setError("Failed to load alerts");
        setLoading(false);
      });
  };

  useEffect(() => { loadAlerts(); }, []);

  const resolveAlert = (id) => {
    axios.post(`http://127.0.0.1:8000/api/resolve-api/${id}/`)
      .then(() => loadAlerts())
      .catch(err => console.log("Resolve error:", err));
  };

  const active = alerts.filter(a => a.status !== "resolved");
  const resolved = alerts.filter(a => a.status === "resolved");

  if (loading) return <div style={page}>Loading dashboard...</div>;
  if (error) return <div style={page}>{error}</div>;

  return (
    <div style={page}>

      <h1 style={{ color: "#60a5fa" }}>Police Control Dashboard</h1>

      {/* MAP */}
      <MapContainer
        center={[17.38, 78.48]}
        zoom={11}
        style={{ height: 350, marginTop: 20, borderRadius: 12, overflow: "hidden" }}
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

        <ChangeMapView coords={selectedLocation} />

        {active.map(a => (
          a.latitude && a.longitude && (
            <Circle
              key={a.id}
              center={[a.latitude, a.longitude]}
              radius={80}
              pathOptions={{
                color: "red",
                fillColor: "red",
                fillOpacity: 0.4
              }}
            >
              <Popup>
                <strong>{a.message}</strong><br />
                Status: {a.status}
              </Popup>
            </Circle>
          )
        ))}

        {selectedLocation && (
          <Circle
            center={selectedLocation}
            radius={80}
            pathOptions={{
              color: "#f97316",
              fillColor: "#f97316",
              fillOpacity: 0.4
            }}
          >
            <Popup>Selected Alert Location</Popup>
          </Circle>
        )}

      </MapContainer>

      <h2 style={{ marginTop: 30 }}>Active Alerts</h2>
      <Table alerts={active} resolveAlert={resolveAlert} setSelectedLocation={setSelectedLocation} />

      <h2 style={{ marginTop: 30 }}>Resolved Alerts History</h2>
      <Table alerts={resolved} setSelectedLocation={setSelectedLocation} />

    </div>
  );
}

function Table({ alerts, resolveAlert, setSelectedLocation }) {

  const navigateToLocation = (lat, lon) => {
    const url = `https://www.google.com/maps/dir/?api=1&destination=${lat},${lon}`;
    window.open(url, "_blank");
  };

  if (!alerts.length) {
    return <p style={{ marginTop: 10, color: "white" }}>No alerts found</p>;
  }

  return (
    <table style={table}>
      <thead>
        <tr style={{ textAlign: "left" }}>
          <th style={th}>Device</th>
          <th style={th}>Location</th>
          <th style={th}>Message</th>
          <th style={th}>Status</th>
          <th style={th}>Time</th>
          {resolveAlert && <th style={th}>Action</th>}
        </tr>
      </thead>

      <tbody>
        {alerts.map(a => (
          <tr key={a.id} style={{ borderBottom: "1px solid #2d4c73" }}>

            <td style={td}>{a.device_id}</td>

            <td style={td}>
              {a.latitude},{a.longitude}
              <br />

              <button
                style={navigateBtn}
                onClick={() => navigateToLocation(a.latitude, a.longitude)}
              >
                Navigate
              </button>

              <button
                style={viewBtn}
                onClick={() => setSelectedLocation([a.latitude, a.longitude])}
              >
                View on Map
              </button>
            </td>

            <td style={td}>{a.message}</td>

            <td style={td}>
              <span style={{
                padding: "4px 8px",
                borderRadius: 6,
                background: a.status === "resolved" ? "#16a34a" : "#dc2626",
                color: "white",
                fontSize: 12
              }}>
                {a.status}
              </span>
            </td>

            <td style={td}>{new Date(a.timestamp).toLocaleString()}</td>

            {resolveAlert &&
              <td style={td}>
                <button
                  style={btn}
                  onClick={() => resolveAlert(a.id)}
                >
                  Resolve
                </button>
              </td>
            }

          </tr>
        ))}
      </tbody>
    </table>
  );
}

/* ---------- STYLES ---------- */

const page = {
  padding: 30,
  background: "#0b1f3a",
  minHeight: "100vh",
  color: "white",
  fontFamily: "system-ui, sans-serif"
};

const table = {
  width: "100%",
  marginTop: 15,
  borderCollapse: "collapse",
  background: "#142c4c",
  borderRadius: 12,
  overflow: "hidden",
  boxShadow: "0 6px 18px rgba(0,0,0,0.4)"
};

const th = {
  padding: "14px",
  fontSize: 14,
  fontWeight: 600,
  borderBottom: "1px solid #2d4c73",
  background: "#1f3a5f",
  color: "#f1f5f9"
};

const td = {
  padding: "12px",
  fontSize: 14,
  color: "#e2e8f0"
};

const btn = {
  padding: "6px 14px",
  background: "#2563eb",
  border: "none",
  color: "white",
  borderRadius: 6,
  cursor: "pointer"
};

const navigateBtn = {
  marginTop: 6,
  padding: "4px 10px",
  background: "#16a34a",
  border: "none",
  color: "white",
  borderRadius: 6,
  cursor: "pointer",
  fontSize: 12
};

const viewBtn = {
  marginTop: 6,
  marginLeft: 6,
  padding: "4px 10px",
  background: "#f97316",
  border: "none",
  color: "white",
  borderRadius: 6,
  cursor: "pointer",
  fontSize: 12
};
